import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;

/**
 * COMPOUND - compound interest projection, translated from COBOL 85.
 * Faithful variant: exact COBOL arithmetic behavior takes priority over
 * Java idiom. PERFORM VARYING ... UNTIL has TEST BEFORE semantics - the
 * condition is checked before every iteration, so a zero-year term runs
 * the accrual paragraph zero times. All values are BigDecimal; every
 * store honors the target PICTURE's scale and capacity (high-order
 * digits drop silently, as COBOL does with no ON SIZE ERROR declared).
 */
public final class Compound {

    /** PERFORM VARYING WS-YR FROM 1 BY 1: loop start and step. */
    private static final BigDecimal YEAR_ONE = new BigDecimal("1");

    /** PIC 9(7)V99 capacity (WS-BALANCE, WS-YR-INT, WS-TOTAL-INT). */
    private static final BigDecimal PIC_9_7_V99_MODULUS = new BigDecimal("10000000");

    /** PIC 99V99 capacity (WS-RATE-PCT). */
    private static final BigDecimal PIC_99_V99_MODULUS = new BigDecimal("100");

    /** PIC 9 capacity (WS-TERM). */
    private static final BigDecimal PIC_9_MODULUS = new BigDecimal("10");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        // MAIN-PARA (compound.cbl:31-42): ACCEPT + FUNCTION NUMVAL.
        String acctId = readLine(in);                                        // WS-ACCT-ID PIC X(8)
        BigDecimal balance = numval(readLine(in), 2, PIC_9_7_V99_MODULUS);   // WS-BALANCE PIC 9(7)V99
        BigDecimal ratePct = numval(readLine(in), 2, PIC_99_V99_MODULUS);    // WS-RATE-PCT PIC 99V99
        BigDecimal term = numval(readLine(in), 0, PIC_9_MODULUS);            // WS-TERM PIC 9

        BigDecimal totalInt = BigDecimal.ZERO;                               // WS-TOTAL-INT (VALUE ZERO)

        // PERFORM ACCRUE-PARA VARYING WS-YR FROM 1 BY 1 UNTIL WS-YR > WS-TERM
        // (compound.cbl:40-41): TEST BEFORE - zero iterations when term is 0.
        for (BigDecimal yr = YEAR_ONE; yr.compareTo(term) <= 0; yr = yr.add(YEAR_ONE)) {
            // ACCRUE-PARA (compound.cbl:44-47):
            // COMPUTE WS-YR-INT ROUNDED = WS-BALANCE * WS-RATE-PCT / 100 -
            // the /100 is an exact decimal shift; ROUNDED settles half away
            // from zero into PIC 9(7)V99.
            BigDecimal yrInt = balance.multiply(ratePct)
                    .movePointLeft(2)
                    .setScale(2, RoundingMode.HALF_UP)
                    .remainder(PIC_9_7_V99_MODULUS);
            // ADD WS-YR-INT TO WS-TOTAL-INT / TO WS-BALANCE: capacity wraps.
            totalInt = totalInt.add(yrInt).remainder(PIC_9_7_V99_MODULUS);
            balance = balance.add(yrInt).remainder(PIC_9_7_V99_MODULUS);
        }

        // PRINT-PARA (compound.cbl:48-53): KEY=VALUE contract on stdout.
        StringBuilder out = new StringBuilder();
        out.append("ACCT_ID=").append(acctId).append('\n');
        out.append("TOTAL_INT=").append(totalInt.toPlainString()).append('\n');
        out.append("END_BAL=").append(balance.toPlainString()).append('\n');
        System.out.print(out);
    }

    private static String readLine(BufferedReader in) throws IOException {
        String line = in.readLine();
        return line == null ? "" : line.trim();
    }

    /**
     * FUNCTION NUMVAL followed by the COMPUTE store into the target
     * PICTURE: extra decimals truncate toward zero and integer digits
     * beyond the PICTURE's capacity drop silently. COBOL input-conversion
     * behavior with no ON SIZE ERROR declared.
     */
    private static BigDecimal numval(String s, int scale, BigDecimal capacity) {
        try {
            BigDecimal v = new BigDecimal(s.trim());
            if (v.signum() < 0) {
                throw new NumberFormatException("negative value for unsigned PICTURE");
            }
            return v.setScale(scale, RoundingMode.DOWN).remainder(capacity);
        } catch (NumberFormatException e) {
            System.err.println("COMPOUND: invalid numeric input: " + s);
            System.exit(3);
            return BigDecimal.ZERO; // unreachable
        }
    }
}
